# Full Bicep template for a Deployment Stack that replaces a landing zone blueprint
# This single .bicep file replaces: RG artifact + ARM template artifact + role assignment artifact

cat << 'EOF' > landing_zone_baseline.bicep
targetScope = 'subscription'

param subscriptionLocation string = 'eastus'
param appTeamGroupObjectId string
@description('Log Analytics workspace resource ID in management subscription')
param logAnalyticsWorkspaceId string

// ── Resource Groups (replaces blueprint resourceGroup artifacts) ──
resource rgWorkloads 'Microsoft.Resources/resourceGroups@2023-07-01' = {
  name: 'rg-workloads-prod-${subscriptionLocation}'
  location: subscriptionLocation
  tags: { Environment: 'prod', ManagedBy: 'deployment-stack' }
}

resource rgMonitoring 'Microsoft.Resources/resourceGroups@2023-07-01' = {
  name: 'rg-monitoring-prod-${subscriptionLocation}'
  location: subscriptionLocation
  tags: { Environment: 'prod', Purpose: 'Monitoring' }
}

// ── Key Vault (replaces key-vault ARM template artifact) ──
module keyVault 'key_vault.bicep' = {
  name: 'key-vault'
  scope: rgWorkloads
  params: {
    location: subscriptionLocation
    keyVaultAdminObjectId: appTeamGroupObjectId
  }
}

// ── Diagnostic Storage Account (replaces diag-storage-account artifact) ──
module diagStorage 'diag_storage.bicep' = {
  name: 'diag-storage'
  scope: rgMonitoring
  params: {
    location: subscriptionLocation
    logAnalyticsWorkspaceId: logAnalyticsWorkspaceId
  }
}

// ── Role Assignment (replaces role assignment artifact) ──
resource appTeamContributor 'Microsoft.Authorization/roleAssignments@2022-04-01' = {
  name: guid(subscription().id, appTeamGroupObjectId, 'Contributor')
  properties: {
    roleDefinitionId: subscriptionResourceId('Microsoft.Authorization/roleDefinitions', 'b24988ac-6180-42a0-ab88-20f7382dd24c')
    principalId: appTeamGroupObjectId
    principalType: 'Group'
  }
}
EOF

# Deploy as a Deployment Stack
az stack sub create \
  --name 'landing-zone-baseline-stack' \
  --location eastus \
  --template-file landing_zone_baseline.bicep \
  --parameters subscriptionLocation=eastus \
              appTeamGroupObjectId='<app-team-oid>' \
              logAnalyticsWorkspaceId='/subscriptions/<mgmt-sub>/resourceGroups/rg-management-prod-eastus/providers/Microsoft.OperationalInsights/workspaces/log-management-prod-eastus' \
  --deny-settings-mode DenyDelete \
  --deny-settings-apply-to-child-scopes \
  --action-on-unmanage detachAll
